pub enum NetcReceiveResultView {
    Received { sender: EndPoint, message: Seq<u8> },
    TimedOut,
    Error,
}

impl View for NetcReceiveResult {
    type V = NetcReceiveResultView;
    closed spec fn view(&self) -> NetcReceiveResultView {
        match self {
            NetcReceiveResult::Received { sender, message } =>
                NetcReceiveResultView::Received { sender: *sender, message: message@ },
            NetcReceiveResult::TimedOut => NetcReceiveResultView::TimedOut,
            NetcReceiveResult::Error => NetcReceiveResultView::Error,
        }
    }
}

